//! Place-assertion spec functions of property `invalid_lat_alarm_on` -- one per
//! point its decoration binds (unbound points carry `true`, design D5).

#![allow(non_snake_case)]
#![allow(unused_imports)]

use data::*;
use vstd::prelude::*;

use crate::assertions::*;
use crate::system_state::SystemState;

verus! {

/** property invalid_lat_alarm_on, bound 'after oi' (place after_oi)
  */
pub open spec fn sys_assert_invalid_lat_alarm_on_after_oi(st: SystemState) -> bool
{
  (sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property invalid_lat_alarm_on, bound 'at ts_oi_done' (place post_join_1)
  */
pub open spec fn sys_assert_invalid_lat_alarm_on_post_join_1(st: SystemState) -> bool
{
  (sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property invalid_lat_alarm_on, bound 'before dmf' (place before_dmf)
  */
pub open spec fn sys_assert_invalid_lat_alarm_on_before_dmf(st: SystemState) -> bool
{
  (sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property invalid_lat_alarm_on, bound 'after dmf' (place after_dmf)
  */
pub open spec fn sys_assert_invalid_lat_alarm_on_after_dmf(st: SystemState) -> bool
{
  (sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property invalid_lat_alarm_on, bound 'after mmi' (place after_mmi)
  *   MA precondition plumbing + REQ_MMI_4 (invalid alarm temp -> interface failure)
  */
pub open spec fn sys_assert_invalid_lat_alarm_on_after_mmi(st: SystemState) -> bool
{
  ((sysProp_REQ_MMI_4(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.mon_interface_failure) && sysProp_REQ_MMI_5(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.mon_interface_failure)) &&
    sysProp_REQ_MMI_6(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.lower_alarm_temp, st.upper_alarm_temp, st.mon_interface_failure)) &&
    (!(st.mon_interface_failure.flag) ==>
      ((sysProp_Figure_A_7(st.lower_alarm_temp, st.upper_alarm_temp) && sysProp_Table_A_12_LowerAlarmTemp(st.lower_alarm_temp)) &&
        sysProp_Table_A_12_UpperAlarmTemp(st.upper_alarm_temp)))
}

/** property invalid_lat_alarm_on, bound 'after mmm' (place after_mmm)
  *   invalid lower alarm temp -> interface failure (REQ_MMI_4) -> monitor_status false -> not Normal
  */
pub open spec fn sys_assert_invalid_lat_alarm_on_after_mmm(st: SystemState) -> bool
{
  ((((sysProp_REQ_MMI_4(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.mon_interface_failure) && sysProp_REQ_MMI_5(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.mon_interface_failure)) &&
    sysProp_REQ_MMI_6(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.lower_alarm_temp, st.upper_alarm_temp, st.mon_interface_failure)) &&
    (!(st.mon_interface_failure.flag) ==>
      ((sysProp_Figure_A_7(st.lower_alarm_temp, st.upper_alarm_temp) && sysProp_Table_A_12_LowerAlarmTemp(st.lower_alarm_temp)) &&
        sysProp_Table_A_12_UpperAlarmTemp(st.upper_alarm_temp)))) &&
    sysProp_NormalModeImpliesNoInterfaceFailure(st.monitor_mode, st.mon_interface_failure)) &&
    sysProp_InvalidLATMonitorNotNormal(st.lower_alarm_tempWstatus, st.monitor_mode)
}

/** property invalid_lat_alarm_on, bound 'after ma' (place after_ma)
  *   end-to-end: invalid lower alarm temp & past startup implies alarm on
  */
pub open spec fn sys_assert_invalid_lat_alarm_on_after_ma(st: SystemState) -> bool
{
  sysProp_InvalidLATAlarmOn(st.lower_alarm_tempWstatus, st.monitor_mode, st.alarm_control)
}

} // verus!
